// Código para nó Code do n8n
// Valida se o horário solicitado está dentro da agenda do funcionário
// Pega os dados do webhook (data_e_hora)
const webhookData = $input.first().json.body;
const dataHoraSolicitada = $('Webhook').first().json.body.data_e_hora;
const funcionario = $('Webhook').first().json.body.funcionario;

// Busca os dados da agenda do funcionário atual (vem do nó set anterior)
const agendaData = $input.all().find(item => 
  item.json.agenda && item.json.agenda === funcionario
);

if (!agendaData) {
  return [{
    json: {
      ...webhookData,
      status: 'erro',
      mensagem: `Agenda não encontrada para o funcionário: ${funcionario}`,
      horario_disponivel: false
    }
  }];
}

// Função para garantir que a data seja interpretada no timezone -03:00
function criarDataComTimezone(dataStr) {
  // Se a string já tiver timezone, usa como está
  if (dataStr.includes('T') && (dataStr.includes('+') || dataStr.includes('-') || dataStr.endsWith('Z'))) {
    return new Date(dataStr);
  }

  // Se não tiver timezone, adiciona -03:00
  let dataComTimezone;
  if (dataStr.includes('T')) {
    // Formato ISO sem timezone
    dataComTimezone = dataStr + '-03:00';
  } else if (dataStr.includes(' ')) {
    // Formato brasileiro (dd/mm/yyyy hh:mm:ss ou yyyy-mm-dd hh:mm:ss)
    dataComTimezone = dataStr.replace(' ', 'T') + '-03:00';
  } else {
    // Outros formatos, tenta adicionar timezone
    dataComTimezone = dataStr + '-03:00';
  }

  return new Date(dataComTimezone);
}

// Converte a data solicitada para objeto Date mantendo o timezone -03:00
const dataHora = criarDataComTimezone(dataHoraSolicitada);
const diaSemana = dataHora.toLocaleDateString('pt-BR', { weekday: 'long', timeZone: 'America/Sao_Paulo' });

// Mapeia os dias da semana
const diasSemanaMap = {
  'segunda-feira': 'segunda-feira',
  'terça-feira': 'terça-feira', 
  'quarta-feira': 'quarta-feira',
  'quinta-feira': 'quinta-feira',
  'sexta-feira': 'sexta-feira',
  'sábado': 'sábado',
  'domingo': 'domingo'
};

const diaAtual = diasSemanaMap[diaSemana];

// Verifica se o funcionário trabalha no dia solicitado
const horariosDia = agendaData.json[diaAtual];

if (!horariosDia || horariosDia === 'não') {
  return [{
    json: {
      ...webhookData,
      status: 'indisponivel',
      mensagem: `${funcionario} não trabalha no dia ${diaAtual}`,
      dia_semana: diaAtual,
      horario_funcionario: horariosDia,
      horario_disponivel: false,
      data_hora_original: dataHoraSolicitada,
      timezone: '-03:00'
    }
  }];
}

// Extrai o horário solicitado (hora e minuto) considerando o timezone
const horaSolicitada = dataHora.getHours();
const minutoSolicitado = dataHora.getMinutes();
const horarioSolicitadoMinutos = horaSolicitada * 60 + minutoSolicitado;

// Parseia os horários de trabalho (formato: "09:00 as 18:00")
const [inicioStr, fimStr] = horariosDia.split(' as ');
const [horaInicio, minutoInicio] = inicioStr.split(':').map(Number);
const [horaFim, minutoFim] = fimStr.split(':').map(Number);

const inicioMinutos = horaInicio * 60 + minutoInicio;
const fimMinutos = horaFim * 60 + minutoFim;

// Verifica se o horário solicitado está dentro do expediente
const dentroDoHorario = horarioSolicitadoMinutos >= inicioMinutos && 
                       horarioSolicitadoMinutos <= fimMinutos;

// Formata horários para exibição
const formatarHorario = (horas, minutos) => 
  `${horas.toString().padStart(2, '0')}:${minutos.toString().padStart(2, '0')}`;

// Formata a data/hora com timezone para retorno
const formatarDataHoraComTimezone = (data) => {
  const ano = data.getFullYear();
  const mes = (data.getMonth() + 1).toString().padStart(2, '0');
  const dia = data.getDate().toString().padStart(2, '0');
  const hora = data.getHours().toString().padStart(2, '0');
  const minuto = data.getMinutes().toString().padStart(2, '0');
  const segundo = data.getSeconds().toString().padStart(2, '0');

  return `${ano}-${mes}-${dia}T${hora}:${minuto}:${segundo}-03:00`;
};

const resultado = {
  ...webhookData,
  status: dentroDoHorario ? 'disponivel' : 'fora_do_horario',
  mensagem: dentroDoHorario 
    ? `Horário disponível para ${funcionario}` 
    : `Horário fora do expediente de ${funcionario}`,
  dia_semana: diaAtual,
  horario_solicitado: formatarHorario(horaSolicitada, minutoSolicitado),
  horario_funcionario: horariosDia,
  expediente_inicio: formatarHorario(horaInicio, minutoInicio),
  expediente_fim: formatarHorario(horaFim, minutoFim),
  horario_disponivel: dentroDoHorario,
  data_hora_original: dataHoraSolicitada,
  data_hora_processada: formatarDataHoraComTimezone(dataHora),
  timezone: '-03:00'
};

return [{ json: resultado }];

