// Buscar dados do nó anterior
const dadosDoCode = $('Code').item;
const dados = dadosDoCode.json;

function gerarIntervalosIndividuais(expedienteInicio, expedienteFim, dataOriginal, timezone) {
  const intervalos = [];

  // Extrair a data da data_hora_processada
  const dataBase = dataOriginal.split('T')[0]; // '2025-08-05'

  // Converter horários para números
  const [horaInicio, minutoInicio] = expedienteInicio.split(':').map(Number);
  const [horaFim, minutoFim] = expedienteFim.split(':').map(Number);

  // Gerar intervalos de 1 hora
  let horaAtual = horaInicio;
  let minutoAtual = minutoInicio;

  while (horaAtual < horaFim) {
    const proximaHora = horaAtual + 1;

    // Se ultrapassar o expediente, ajustar para o fim
    const horaFinal = proximaHora > horaFim ? horaFim : proximaHora;
    const minutoFinal = proximaHora > horaFim ? minutoFim : 0;

    // Formatar horários com zero à esquerda
    const horaInicioFormatada = String(horaAtual).padStart(2, '0');
    const minutoInicioFormatado = String(minutoAtual).padStart(2, '0');
    const horaFimFormatada = String(horaFinal).padStart(2, '0');
    const minutoFimFormatado = String(minutoFinal).padStart(2, '0');

    const intervalo = {
      inicio: `${dataBase}T${horaInicioFormatada}:${minutoInicioFormatado}:00${timezone}`,
      fim: `${dataBase}T${horaFimFormatada}:${minutoFimFormatado}:00${timezone}`,
      horario_inicio: `${horaInicioFormatada}:${minutoInicioFormatado}`,
      horario_fim: `${horaFimFormatada}:${minutoFimFormatado}`,
      data: dataBase,
      dia_semana: dados.dia_semana,
      funcionario: dados.mensagem ? dados.mensagem.split(' para ')[1] || 'Funcionário' : 'Funcionário'
    };

    intervalos.push(intervalo);

    // Avançar para o próximo horário
    horaAtual = proximaHora;
    minutoAtual = 0;

    // Se chegou ao fim do expediente, parar
    if (horaAtual >= horaFim) break;
  }

  return intervalos;
}

// Gerar intervalos usando os dados do expediente
const intervalosIndividuais = gerarIntervalosIndividuais(
  dados.expediente_inicio, 
  dados.expediente_fim, 
  dados.data_hora_processada,
  dados.timezone
);

// Retornar array de intervalos individuais
return intervalosIndividuais;

// Código para n8n - Node Code (Versão Corrigida)

// Pega os dados de entrada
const inputData = $input.all();

// Debug: vamos ver como os dados estão chegando
console.log('Dados de entrada:', JSON.stringify(inputData, null, 2));

let horarios = [];

// Tenta diferentes formas de extrair os horários
if (Array.isArray(inputData)) {
  // Cenário 1: Cada item do inputData é um horário
  if (inputData[0] && inputData[0].json && inputData[0].json.inicio) {
    horarios = inputData.map(item => item.json);
  }
  // Cenário 2: Os horários estão numa propriedade específica do primeiro item
  else if (inputData[0] && inputData[0].json) {
    const primeiroItem = inputData[0].json;

    // Verifica se há uma propriedade que seja array
    for (const key in primeiroItem) {
      if (Array.isArray(primeiroItem[key])) {
        horarios = primeiroItem[key];
        break;
      }
    }

    // Se não encontrou array em propriedades, talvez o próprio item seja o array
    if (horarios.length === 0 && Array.isArray(primeiroItem)) {
      horarios = primeiroItem;
    }
  }
}

// Debug: vamos ver os horários extraídos
console.log('Horários extraídos:', JSON.stringify(horarios, null, 2));

// Verifica se conseguimos extrair os horários corretamente
if (!Array.isArray(horarios) || horarios.length === 0) {
  return [
    {
      json: {
        erro: "Não foi possível extrair os horários dos dados de entrada",
        dadosRecebidos: inputData,
        mensagem: "Verifique a estrutura dos dados de entrada"
      }
    }
  ];
}

// Filtra apenas os horários disponíveis
const horariosDisponiveis = horarios.filter(horario => {
  // Aceita tanto string "true" quanto boolean true
  return horario.disponibilidade === "true" || horario.disponibilidade === true;
});

if (horariosDisponiveis.length === 0) {
  // Retorna um item informando que não há horários disponíveis
  return [
    {
      json: {
        mensagem: "Não há horários disponíveis para este dia.",
        horariosDisponiveis: [],
        totalDisponiveis: 0,
        totalAnalisados: horarios.length
      }
    }
  ];
}

// Formata os horários para exibição
const horariosFormatados = horariosDisponiveis.map(horario => {
  const data = new Date(horario.inicio);
  return data.toLocaleTimeString('pt-BR', { 
    hour: '2-digit', 
    minute: '2-digit',
    timeZone: 'America/Sao_Paulo'
  });
});

// Extrai a data do primeiro horário para mostrar o dia
const dataExemplo = new Date(horariosDisponiveis[0].inicio);
const dataFormatada = dataExemplo.toLocaleDateString('pt-BR', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  timeZone: 'America/Sao_Paulo'
});

// Monta a mensagem final
const mensagemFinal = `Tenho esses horários disponíveis para ${dataFormatada}: ${horariosFormatados.join(', ')}. Qual se encaixa melhor?`;

// Retorna no formato que o n8n espera
return [
  {
    json: {
      mensagem: mensagemFinal,
      horariosDisponiveis: horariosDisponiveis,
      horariosFormatados: horariosFormatados,
      dataFormatada: dataFormatada,
      totalDisponiveis: horariosDisponiveis.length,
      totalAnalisados: horarios.length
    }
  }
];

