  'segunda-feira': 'segunda-feira',
  'terça-feira': 'terça-feira', 
  'quarta-feira': 'quarta-feira',
  'quinta-feira': 'quinta-feira',
  'sexta-feira': 'sexta-feira',
  'sábado': 'sábado',
  'domingo': 'domingo'
};

const diaAtual = diasSemanaMap[diaSemana];

// Verifica se o funcionário trabalha no dia solicitado
const horariosDia = agendaData[diaAtual];

if (!horariosDia || horariosDia === 'não') {
  return [{
    json: {
      status: 'indisponivel',
      mensagem: `${funcionario} não trabalha no dia ${diaAtual}`,
      funcionario: funcionario,
      dia_semana: diaAtual,
      horario_funcionario: horariosDia,
